/**
 * OpenShift ImageStream API adapter for backup image discovery
 *
 * This adapter uses OpenShift's ImageStream API to discover and validate
 * backup images stored in the internal registry.
 *
 * API Endpoints Used:
 * - /apis/image.openshift.io/v1/namespaces/{namespace}/imagestreams
 * - /apis/image.openshift.io/v1/namespaces/{namespace}/imagestreamtags/{name}:{tag}
 *
 * MVP Scope:
 * - OpenShift internal registry only
 * - Images tagged with :latest
 * - Filtered by workspace labels
 */
export class OpenShiftRegistryAdapter implements IRegistryAdapter {
  private readonly customObjectAPI: ReturnType<typeof prepareCustomObjectAPI>;
  private readonly apiGroup = 'image.openshift.io';
  private readonly apiVersion = 'v1';
  private readonly timeout: number;

  constructor(kubeConfig: k8s.KubeConfig) {
    this.customObjectAPI = prepareCustomObjectAPI(kubeConfig);
    this.timeout = REGISTRY_QUERY_TIMEOUT_SECONDS * 1000; // Convert to milliseconds
  }

  /**
   * List all backup images in a namespace
   *
   * Queries OpenShift ImageStream API to find all ImageStreams that represent
   * workspace backups. Images are identified by the presence of the
   * DevWorkspace ID label (controller.devfile.io/devworkspace_id).
   *
   * @param namespace - Kubernetes namespace to query
   * @returns Promise resolving to array of backup images
   * @throws Error if registry query fails or times out
   */
  async listBackupImages(namespace: string): Promise<IBackupImage[]> {
    try {
      logger.info(`Listing backup images in namespace: ${namespace}`);

      // Query ImageStreams in the namespace with timeout
      const response = await this.withTimeout(
        this.customObjectAPI.listNamespacedCustomObject({
          group: this.apiGroup,
          version: this.apiVersion,
          namespace,
          plural: 'imagestreams',
        }),
        this.timeout,
        `Registry query timeout for namespace ${namespace}`,
      );

      const imageStreams = (response as unknown as { items: ImageStream[] }).items;

      // Filter and map ImageStreams to backup images
      const backupImages: IBackupImage[] = [];

      for (const imageStream of imageStreams) {
        // Check if ImageStream has DevWorkspace ID label (set by DWO BackupCronJob controller)
        const workspaceId = imageStream.metadata.labels?.[DEVWORKSPACE_BACKUP_LABELS.WORKSPACE_ID];

        if (!workspaceId) {
          logger.debug(
            `ImageStream ${imageStream.metadata.name} has no ${DEVWORKSPACE_BACKUP_LABELS.WORKSPACE_ID} label, skipping`,
          );
          continue;
        }

        // DWO names the ImageStream after the workspace
        const workspaceName = imageStream.metadata.name;

        // Get the :latest tag information
        const latestTag = imageStream.status?.tags?.find(
          tag => tag.tag === BACKUP_IMAGE_DEFAULT_TAG,
        );

        if (!latestTag || !latestTag.items || latestTag.items.length === 0) {
          // ImageStream exists but has no :latest tag — no backup image available yet.
          // Surface it in the API with UNAVAILABLE status so the frontend can display it.
          logger.debug(
            `ImageStream ${imageStream.metadata.name} has no :latest tag, marking as unavailable`,
          );
          backupImages.push({
            workspaceName,
            imageUrl: '',
            timestamp: '', // Empty - no backup has completed yet
            sizeBytes: 0,
            labels: {
              [DEVWORKSPACE_BACKUP_ANNOTATIONS.LAST_BACKUP_SUCCESSFUL]: BackupStatus.UNAVAILABLE,
            },
          });
          continue;
        }

        // Get the most recent image (first in items array)
        const latestImage = latestTag.items[0];

        // Construct full image URL
        const imageUrl = `${OPENSHIFT_INTERNAL_REGISTRY_HOSTNAME}:${OPENSHIFT_INTERNAL_REGISTRY_PORT}/${namespace}/${imageStream.metadata.name}:${BACKUP_IMAGE_DEFAULT_TAG}`;

        // Get image size and labels by querying ImageStreamTag
        const metadata = await this.getImageStreamTagMetadata(
          namespace,
          imageStream.metadata.name,
          BACKUP_IMAGE_DEFAULT_TAG,
        );

        backupImages.push({
          workspaceName,
          imageUrl,
          timestamp: latestImage.created,
          sizeBytes: metadata.sizeBytes,
          labels: metadata.labels,
        });
      }

      logger.info(`Found ${backupImages.length} backup images in namespace: ${namespace}`);
      return backupImages;
    } catch (e) {
      if ((e as Error).message.includes('timeout')) {
        throw createError(e, BACKUP_ERROR_CODES.TIMEOUT, 'Registry query timeout');
      }
      throw createError(
        e,
        BACKUP_ERROR_CODES.REGISTRY_API_ERROR,
        `Unable to list backup images in namespace ${namespace}`,
      );
    }
  }

  /**
   * Get metadata for a specific backup image
   *
   * Queries ImageStreamTag API to retrieve detailed metadata including
   * size, labels, and timestamp for a specific backup image.
   *
   * @param imageUrl - Full URL to the backup image
   * @returns Promise resolving to image metadata
   * @throws Error if image not found or metadata cannot be retrieved
   */
  async getImageMetadata(imageUrl: string): Promise<IImageMetadata> {
    try {
      // Parse image URL: registry/namespace/name:tag
      const parsedUrl = this.parseImageUrl(imageUrl);

      logger.info(`Getting metadata for image: ${imageUrl}`);

      // Query ImageStreamTag for detailed metadata
      const metadata = await this.getImageStreamTagMetadata(
        parsedUrl.namespace,
        parsedUrl.name,
        parsedUrl.tag,
      );

      return metadata;
    } catch (e) {
      throw createError(
        e,
        BACKUP_ERROR_CODES.BACKUP_IMAGE_NOT_FOUND,
        `Unable to get metadata for image: ${imageUrl}`,
      );
    }
  }

  /**
   * Validate that a backup image is accessible
   *
   * Attempts to retrieve image metadata to verify accessibility.
   * Used for cross-cluster restore validation.
   *
   * @param imageUrl - Full URL to the backup image
   * @returns Promise resolving to true if image is accessible
   */
  async validateImageAccessibility(imageUrl: string): Promise<boolean> {
    try {
      await this.getImageMetadata(imageUrl);
      return true;
    } catch (e) {
      logger.warn(`Image not accessible: ${imageUrl}`, e);
      return false;
    }
  }

  /**
   * Get ImageStreamTag metadata
   *
   * Helper method to query OpenShift ImageStreamTag API for detailed
   * image metadata including size and labels.
   *
   * @param namespace - Kubernetes namespace
   * @param name - ImageStream name
   * @param tag - Image tag
   * @returns Promise resolving to image metadata
   */
  private async getImageStreamTagMetadata(
    namespace: string,
    name: string,
    tag: string,
  ): Promise<IImageMetadata> {
    try {
      const imageStreamTagName = `${name}:${tag}`;

      const response = await this.withTimeout(
        this.customObjectAPI.getNamespacedCustomObject({
          group: this.apiGroup,
          version: this.apiVersion,
          namespace,
          plural: 'imagestreamtags',
          name: imageStreamTagName,
        }),
        this.timeout,
        `Registry query timeout for ImageStreamTag ${imageStreamTagName}`,
      );

      const imageStreamTag = response as unknown as ImageStreamTag;

      // Extract metadata from ImageStreamTag
      // Size calculation priority:
      // 1. dockerImageLayers (single-arch images) - sum of all layer sizes
      // 2. dockerImageManifests (manifest lists/multi-arch) - sum of all manifest sizes
      // 3. dockerImageMetadata.Size (fallback) - often unreliable (just manifest size)
      const layersSize =
        imageStreamTag.image.dockerImageLayers?.reduce(
          (sum, layer) => sum + (layer.size || 0),
          0,
        ) || 0;

      const manifestsSize =
        imageStreamTag.image.dockerImageManifests?.reduce(
          (sum, manifest) => sum + (manifest.manifestSize || 0),
          0,
        ) || 0;

      const metadataSize = imageStreamTag.image.dockerImageMetadata.Size || 0;

      let sizeBytes = 0;
      if (layersSize > 0) {
        // Single-architecture image with layers
        sizeBytes = layersSize;
        logger.debug(`Image ${name}:${tag} size from layers: ${sizeBytes} bytes`);
      } else if (manifestsSize > 0) {
        // Manifest list (multi-architecture image)
        sizeBytes = manifestsSize;
        logger.debug(`Image ${name}:${tag} size from manifests: ${sizeBytes} bytes`);
      } else {
        // Fallback to metadata size (often unreliable)
        sizeBytes = metadataSize;
        logger.warn(
          `Image ${name}:${tag} has no layer or manifest data, using metadata size: ${sizeBytes} bytes (may be inaccurate)`,
        );
      }
      const labels = imageStreamTag.image.dockerImageMetadata.Config?.Labels || {};

      // DWO names ImageStreams after workspaces; use the ImageStream name as workspace name
      const workspaceName = labels[DEVWORKSPACE_BACKUP_LABELS.WORKSPACE_NAME] || name;
      const workspaceNamespace = namespace;

      // Get timestamp from image metadata (creation time or backup label)
      const timestamp =
        labels['backup.timestamp'] ||
        imageStreamTag.metadata.creationTimestamp ||
        new Date().toISOString();

      return {
        workspaceName,
        namespace: workspaceNamespace,
        timestamp,
        sizeBytes,
        labels,
      };
    } catch (e) {
      throw createError(
        e,
        BACKUP_ERROR_CODES.REGISTRY_API_ERROR,
        `Unable to get ImageStreamTag metadata: ${name}:${tag}`,
      );
    }
  }

  /**
   * Parse image URL into components
   *
   * Expected format: registry/namespace/name:tag
   * Example: image-registry.openshift-image-registry.svc:5000/user-che/my-workspace:latest
   *
   * @param imageUrl - Full image URL
   * @returns Parsed URL components
   * @throws Error if URL format is invalid or registry is not allowed
   */
  private parseImageUrl(imageUrl: string): {
    registry: string;
    namespace: string;
    name: string;
    tag: string;
  } {
    // Normalize URL: add :latest tag if missing for validation
    let normalizedUrl = imageUrl;
    if (!imageUrl.includes(':')) {
      // No port or tag - need to check if it's registry:port or just missing tag
      const parts = imageUrl.split('/');
      if (parts.length >= 3) {
        // Has registry/namespace/name format - add default tag
        normalizedUrl = `${imageUrl}:${BACKUP_IMAGE_DEFAULT_TAG}`;
      }
    } else {
      // Check if the colon is part of registry:port or name:tag
      const lastSlashIndex = imageUrl.lastIndexOf('/');
      const colonAfterSlash = imageUrl.indexOf(':', lastSlashIndex);
      if (colonAfterSlash === -1) {
        // Colon is in registry:port, no tag present
        normalizedUrl = `${imageUrl}:${BACKUP_IMAGE_DEFAULT_TAG}`;
      }
    }

    // SECURITY: Validate URL format against expected pattern
    if (!BACKUP_IMAGE_URL_PATTERN.test(normalizedUrl)) {
      throw createError(
        new Error('Invalid image URL format'),
        BACKUP_ERROR_CODES.INVALID_IMAGE_URL,
        `Image URL does not match expected format: ${imageUrl}`,
      );
    }

    // SECURITY: Ensure it's OpenShift internal registry only (MVP Phase 1 scope)
    const registryPart = normalizedUrl.split('/')[0].split(':')[0];
    const isInternal =
      registryPart === OPENSHIFT_INTERNAL_REGISTRY_HOSTNAME ||
      registryPart === 'image-registry.openshift-image-registry' ||
      registryPart.startsWith('image-registry.openshift-image-registry.');

    if (!isInternal) {
      throw createError(
        new Error('External registry not allowed'),
        BACKUP_ERROR_CODES.INVALID_IMAGE_URL,
        'Only OpenShift internal registry is allowed in Phase 1',
      );
    }

    // Parse the normalized URL
    const parts = normalizedUrl.split('/');
    if (parts.length < 3) {
      throw createError(
        new Error('Invalid image URL structure'),
        BACKUP_ERROR_CODES.INVALID_IMAGE_URL,
        `Invalid image URL format: ${imageUrl}`,
      );
    }

    const registry = parts[0];
    const namespace = parts[1];
    const nameAndTag = parts.slice(2).join('/'); // Handle image names with /

    // Split name and tag
    const [name, tag = BACKUP_IMAGE_DEFAULT_TAG] = nameAndTag.split(':');

    return {
      registry,
      namespace,
      name,
      tag,
    };
  }

  /**
   * Execute a promise with timeout
   *
   * Wraps a promise with a timeout to prevent hanging registry queries.
   *
   * @param promise - Promise to execute
   * @param timeoutMs - Timeout in milliseconds
   * @param errorMessage - Error message if timeout occurs
   * @returns Promise that resolves or rejects based on the original promise or timeout
   */
  private async withTimeout<T>(
    promise: Promise<T>,
    timeoutMs: number,
    errorMessage: string,
  ): Promise<T> {
    const timeoutPromise = new Promise<never>((_, reject) => {
      setTimeout(() => reject(new Error(errorMessage)), timeoutMs);
    });

    return Promise.race([promise, timeoutPromise]);
  }
}
